from flask import Flask, request, jsonify
import tensorflow as tf
import os
import pandas as pd
from werkzeug.utils import secure_filename
from tensorflow.keras.preprocessing.image import ImageDataGenerator

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'csv'}
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

model = tf.keras.models.Sequential([
    tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(128, 128, 3)),
    tf.keras.layers.MaxPooling2D((2, 2)),
    tf.keras.layers.Conv2D(64, (3, 3), activation='relu'),
    tf.keras.layers.MaxPooling2D((2, 2)),
    tf.keras.layers.Conv2D(128, (3, 3), activation='relu'),
    tf.keras.layers.MaxPooling2D((2, 2)),
    tf.keras.layers.Flatten(),
    tf.keras.layers.Dense(128, activation='relu'),
    tf.keras.layers.Dense(10, activation='softmax')
])

model.compile(optimizer='adam', loss='sparse_categorical_crossentropy', metrics=['accuracy'])

if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(filepath)
        
        data = pd.read_csv(filepath)
        images = data['image_paths'].values
        labels = data['labels'].values
        
        datagen = ImageDataGenerator(rescale=1./255)
        train_generator = datagen.flow_from_dataframe(
            dataframe=data,
            directory='.',
            x_col='image_paths',
            y_col='labels',
            target_size=(128, 128),
            batch_size=32,
            class_mode='raw'
        )
        
        model.fit(train_generator, epochs=5)
        return jsonify({'message': 'Model trained with uploaded data'})
    return jsonify({'error': 'Invalid file format'})

@app.route('/add_example', methods=['POST'])
def add_training_example():
    data = request.get_json()
    image_path = data.get('image_path')
    label = data.get('label')

    # Presume the image is saved in a known location
    new_data = pd.DataFrame({'image_paths': [image_path], 'labels': [label]})
    datagen = ImageDataGenerator(rescale=1./255)
    new_data_gen = datagen.flow_from_dataframe(
        dataframe=new_data,
        directory='.',
        x_col='image_paths',
        y_col='labels',
        target_size=(128, 128),
        batch_size=1,
        class_mode='raw'
    )
    model.fit(new_data_gen, epochs=1)
    return jsonify({'message': 'New example added to training'})

if __name__ == '__main__':
    app.run(debug=True)